example.code:
-- Query pattern: find orders by user and status
SELECT * FROM orders
WHERE user_id = ? AND status = 'pending';

-- Index design: composite index on user_id, status
CREATE INDEX idx_orders_user_status ON orders(user_id, status);

-- Query pattern: find orders by user in a date range
SELECT * FROM orders
WHERE user_id = ? AND created_at BETWEEN ? AND ?;

-- Index design: user_id first (equality), then created_at (range)
CREATE INDEX idx_orders_user_created ON orders(user_id, created_at);

-- Query pattern: get count, total, and order IDs for user (all queries select same columns)
SELECT o.id, o.total_amount FROM orders o
WHERE o.user_id = ? AND o.status = 'completed';

-- Index design: covering index includes columns in SELECT
CREATE INDEX idx_orders_covering ON orders(user_id, status)
    INCLUDE (id, total_amount);

-- Query pattern: recent pending orders (most rows are 'completed' or 'cancelled')
SELECT * FROM orders
WHERE status = 'pending' AND created_at > NOW() - INTERVAL '7 days';

-- Index design: partial index on small subset
CREATE INDEX idx_orders_pending ON orders(created_at)
    WHERE status = 'pending';

-- BAD: Function on indexed column prevents index use
SELECT * FROM users WHERE LOWER(email) = 'test@example.com';

-- Optimizer cannot use email index because the column is transformed

-- GOOD: Keyset pagination using last seen value -- First page: no cursor SELECT * FROM products ORDER BY created_at DESC LIMIT 20;
-- Second page: cursor is created_at value from last row of previous page SELECT * FROM products WHERE created_at < '2024-01-15 10:30:00' ORDER BY created_at DESC LIMIT 20;
-- Supports index scan directly to the position; no need to scan 10000 rows

-- BAD: Individual inserts repeated in application loop
INSERT INTO logs (message) VALUES ('log1');
INSERT INTO logs (message) VALUES ('log2');
INSERT INTO logs (message) VALUES ('log3');
-- ... repeated 1000 times

-- This is 1000 network round-trips and 1000 transaction overheads

-- Create materialized view for expensive aggregation CREATE MATERIALIZED VIEW daily_sales_stats AS SELECT DATE(created_at) as sale_date, COUNT(*) as order_count, SUM(total_amount) as total_revenue, AVG(total_amount) as avg_order_value FROM orders WHERE status = 'delivered' GROUP BY DATE(created_at);
-- Create index on materialized view for fast queries CREATE INDEX idx_sales_stats_date ON daily_sales_stats(sale_date);
-- Refresh periodically (CONCURRENTLY avoids locking) REFRESH MATERIALIZED VIEW CONCURRENTLY daily_sales_stats;
-- Now dashboard queries are fast: they query the view, not the raw table SELECT * FROM daily_sales_stats WHERE sale_date = CURRENT_DATE;
